I have to blog this down.
 
<pre class="lang:sass decode:true">$slugs: "xs", "sm", "md", "lg";
 
body {
  &.debug {

    @for $i from 0 through 12 {
      .col-#{$i} {
        background: darken(#fefefe, $i);
      }

      @each $slug in $slugs {

        .col-#{$slug}-#{$i} {
          @extend .col-#{$i};
        }
      }

    }

  }
}</pre> 

